// components/dashboard/RecentActivity.tsx
'use client'

import { Route } from '../../types'
import { FiMap, FiClock, FiUser, FiCheckCircle, FiXCircle } from 'react-icons/fi'
import Link from 'next/link'

interface RecentActivityProps {
  routes: Route[]
}

export function RecentActivity({ routes }: RecentActivityProps) {
  return (
    <div className="space-y-4">
      {routes.length === 0 ? (
        <div className="text-center py-8">
          <FiMap className="mx-auto text-4xl text-text-light mb-4" />
          <p className="text-text">No routes pending approval</p>
          <p className="text-text-light">All routes have been processed</p>
        </div>
      ) : (
        routes.map(route => (
          <div key={route.id} className="border border-border rounded-lg p-4 hover:shadow-sm transition-shadow">
            <div className="flex items-start justify-between">
              <div className="flex-1">
                <div className="flex items-center space-x-3 mb-2">
                  <h4 className="font-semibold text-text">{route.name}</h4>
                  <span className={`text-xs px-2 py-1 rounded-full ${
                    route.approved 
                      ? 'bg-success/10 text-success' 
                      : 'bg-yellow-100 text-yellow-800'
                  }`}>
                    {route.approved ? 'Approved' : 'Pending'}
                  </span>
                </div>
                
                <p className="text-text-light text-sm mb-3 line-clamp-2">{route.description}</p>
                
                <div className="flex items-center justify-between text-sm text-text-light">
                  <div className="flex items-center space-x-4">
                    <div className="flex items-center">
                      <FiClock className="mr-2" />
                      <span>{route.travel_time_minutes} mins</span>
                    </div>
                    <div className="flex items-center">
                      <FiUser className="mr-2" />
                      <span>{route.vehicle_type}</span>
                    </div>
                  </div>
                  
                  <Link
                    href={`/dashboard/routes`}
                    className="text-primary hover:text-primary-dark text-sm font-medium"
                  >
                    View Details →
                  </Link>
                </div>
              </div>
              
              <div className="flex items-center space-x-2 ml-4">
                <button
                  className="p-2 text-success hover:bg-success/10 rounded-lg"
                  title="Approve"
                >
                  <FiCheckCircle />
                </button>
                <button
                  className="p-2 text-error hover:bg-error/10 rounded-lg"
                  title="Reject"
                >
                  <FiXCircle />
                </button>
              </div>
            </div>
          </div>
        ))
      )}
    </div>
  )
}